import { describe, expect, it } from 'vitest'
import { sanitizeEpisodePayload } from '@/lib/agent/sanitize-episode'

describe('sanitizeEpisodePayload', () => {
  it('fills missing social post fields', () => {
    const result = sanitizeEpisodePayload(
      {
        strategyNote: 'Test strategy',
        agentReasoning: 'Test reasoning',
        content: {
          linkedin: { hook: 'Hello', body: 'World' },
        },
      },
      ['linkedin'],
      'clean professional'
    )

    expect(result.platforms).toEqual(['linkedin'])
    expect(result.content.linkedin?.hook).toBe('Hello')
    expect(result.content.linkedin?.body).toBe('World')
    expect(result.content.linkedin?.hashtags.length).toBeGreaterThanOrEqual(3)
  })

  it('defaults strategy when missing', () => {
    const result = sanitizeEpisodePayload({}, ['x'], 'minimal')
    expect(result.strategyNote.length).toBeGreaterThan(10)
    expect(result.content.x?.body).toBeTruthy()
  })
})

import type {
  ContentEpisodePayload,
  PlatformContent,
  SocialPlatform,
} from "@/lib/agent/types";

function ensureScenePrompts(
  arr: unknown,
  min: number,
  max: number,
  fallbackPrefix: string
) {
  const items = Array.isArray(arr) ? arr : [];
  const mapped = items.slice(0, max).map((item: unknown, i: number) => {
    const o = item as Record<string, unknown>;
    return {
      sceneNumber: typeof o.sceneNumber === "number" ? o.sceneNumber : i + 1,
      description: String(o.description || `Scene ${i + 1}`),
      prompt: String(o.prompt || `${fallbackPrefix} scene ${i + 1}`),
    };
  });
  while (mapped.length < min) {
    mapped.push({
      sceneNumber: mapped.length + 1,
      description: `Scene ${mapped.length + 1}`,
      prompt: `${fallbackPrefix} scene ${mapped.length + 1}`,
    });
  }
  return mapped;
}

function ensureScript(raw: unknown) {
  const o = (raw as Record<string, unknown>) || {};
  return {
    hook: String(o.hook || "Here's what you need to know."),
    body: String(o.body || "Content generated for this topic."),
    cta: String(o.cta || "Learn more in the link below."),
    estimatedDurationSec:
      typeof o.estimatedDurationSec === "number"
        ? Math.min(600, Math.max(30, o.estimatedDurationSec))
        : 75,
  };
}

function ensureYouTube(raw: unknown) {
  const o = (raw as Record<string, unknown>) || {};
  const titles = Array.isArray(o.titleOptions)
    ? o.titleOptions.map(String).filter(Boolean)
    : [];
  const tags = Array.isArray(o.tags) ? o.tags.map(String).filter(Boolean) : [];
  return {
    titleOptions:
      titles.length >= 3
        ? titles.slice(0, 5)
        : [
            ...titles,
            "Generated Title Option",
            "Another Title Option",
            "Third Title Option",
          ].slice(0, 3),
    description: String(
      o.description || "0:00 Hook\n\nFull description with CTA."
    ),
    tags:
      tags.length >= 5
        ? tags
        : [...tags, "content", "business", "tips", "news", "update"].slice(
            0,
            5
          ),
  };
}

function ensureSocialPost(raw: unknown) {
  const o = (raw as Record<string, unknown>) || {};
  const format = ["POST", "THREAD", "CAROUSEL"].includes(String(o.format))
    ? (String(o.format) as "POST" | "THREAD" | "CAROUSEL")
    : "POST";
  const hashtags = Array.isArray(o.hashtags)
    ? o.hashtags.map(String).filter(Boolean)
    : ["content", "business", "tips"];
  return {
    format,
    hook: String(o.hook || "Quick insight:"),
    body: String(o.body || o.content || "Generated social post."),
    hashtags: hashtags.length >= 3 ? hashtags.slice(0, 10) : [...hashtags, "news", "tips"].slice(0, 3),
    suggestedMedia: o.suggestedMedia ? String(o.suggestedMedia) : undefined,
    imagePrompt: o.imagePrompt ? String(o.imagePrompt) : undefined,
    cta: o.cta ? String(o.cta) : undefined,
  };
}

function sanitizePlatformContent(
  content: Record<string, unknown>,
  platforms: SocialPlatform[],
  visualStyle: string
): PlatformContent {
  const result: PlatformContent = {};
  const style = visualStyle || "clean, professional";

  for (const platform of platforms) {
    const raw = (content[platform] as Record<string, unknown> | undefined) ?? {};

    switch (platform) {
      case "youtube_short":
        result.youtube_short = {
          script: ensureScript(raw?.script),
          imagePrompts: ensureScenePrompts(
            raw?.imagePrompts,
            4,
            6,
            style
          ),
          thumbnail: {
            concept: String(
              (raw?.thumbnail as Record<string, unknown>)?.concept ||
                "Bold thumbnail concept"
            ),
            prompt: String(
              (raw?.thumbnail as Record<string, unknown>)?.prompt ||
                `${style} YouTube thumbnail`
            ),
          },
          youtube: ensureYouTube(raw?.youtube),
        };
        break;
      case "youtube_long":
        result.youtube_long = {
          outline: Array.isArray(raw?.outline)
            ? (raw.outline as unknown[]).map((s: unknown) => {
                const sec = s as Record<string, unknown>;
                return {
                  section: String(sec.section || "Section"),
                  durationSec:
                    typeof sec.durationSec === "number" ? sec.durationSec : 120,
                  talkingPoints: Array.isArray(sec.talkingPoints)
                    ? sec.talkingPoints.map(String)
                    : ["Key point"],
                };
              })
            : [{ section: "Intro", durationSec: 60, talkingPoints: ["Hook"] }],
          script: String(raw?.script || "Long-form script generated."),
          brollPrompts: ensureScenePrompts(raw?.brollPrompts, 6, 12, style),
          thumbnail: {
            concept: String(
              (raw?.thumbnail as Record<string, unknown>)?.concept || "Concept"
            ),
            prompt: String(
              (raw?.thumbnail as Record<string, unknown>)?.prompt ||
                `${style} thumbnail`
            ),
          },
          youtube: ensureYouTube(raw?.youtube),
        };
        break;
      case "tiktok":
        result.tiktok = {
          script: ensureScript(raw?.script),
          onScreenText: Array.isArray(raw?.onScreenText)
            ? raw.onScreenText.map(String).slice(0, 8)
            : ["Hook text", "Key point", "CTA"],
          hashtags: Array.isArray(raw?.hashtags)
            ? raw.hashtags.map(String).slice(0, 15)
            : ["fyp", "business", "tips", "news", "content"],
          scenePrompts: ensureScenePrompts(raw?.scenePrompts, 4, 6, style),
          musicMood: raw?.musicMood ? String(raw.musicMood) : undefined,
          caption: String(raw?.caption || "Generated TikTok caption."),
        };
        break;
      case "instagram": {
        const fmt = ["REEL", "POST", "CAROUSEL", "STORY"].includes(
          String(raw?.format)
        )
          ? (String(raw?.format) as "REEL" | "POST" | "CAROUSEL" | "STORY")
          : "REEL";
        result.instagram = {
          format: fmt,
          caption: String(raw?.caption || "Generated Instagram caption."),
          hook: String(raw?.hook || "Stop scrolling."),
          hashtags: Array.isArray(raw?.hashtags)
            ? raw.hashtags.map(String).slice(0, 30)
            : ["instagram", "reels", "business", "content", "tips"],
          reelScript: raw?.reelScript
            ? ensureScript(raw.reelScript)
            : ensureScript(null),
          imagePrompt: raw?.imagePrompt ? String(raw.imagePrompt) : undefined,
        };
        break;
      }
      case "x":
        result.x = ensureSocialPost(raw);
        break;
      case "linkedin":
        result.linkedin = ensureSocialPost(raw);
        break;
      case "facebook":
        result.facebook = ensureSocialPost(raw);
        break;
    }
  }

  return result;
}

export function sanitizeEpisodePayload(
  parsed: Record<string, unknown>,
  platforms: SocialPlatform[],
  visualStyle: string
): ContentEpisodePayload {
  const content = sanitizePlatformContent(
    (parsed.content as Record<string, unknown>) || {},
    platforms,
    visualStyle
  );

  return {
    platforms,
    strategyNote: String(
      parsed.strategyNote ||
        "Content package generated based on brand context and topic."
    ),
    agentReasoning: String(
      parsed.agentReasoning ||
        parsed.reasoning ||
        "Strategic multi-platform content tailored to the brand voice."
    ),
    content,
  };
}

import { z } from 'zod'

// ============================================
// AI Provider
// ============================================
export const AIProviderSchema = z.enum(['openai', 'anthropic', 'xai', 'google'])
export type AIProvider = z.infer<typeof AIProviderSchema>

// ============================================
// Brand Context (TekMarketing DB model)
// ============================================
export const BrandContextSchema = z.object({
  companyName: z.string().min(2),
  voiceDescription: z.string().min(50),
  targetAudience: z.string().min(30),
  productsServices: z.string().min(10),
  keyDifferentiators: z.string().optional(),
  primaryGoals: z.string().min(10),
  contentPillars: z.string().optional(),
  preferredPlatforms: z.string().min(1),
  toneKeywords: z.string().optional(),
  doNotSay: z.string().optional(),
  industry: z.string().optional(),
  website: z.string().url().optional().or(z.literal('')),
  visualStyle: z.string().optional(),
  logoDataUrl: z.string().optional(),
  additionalContext: z.string().optional(),
})

export type BrandContextInput = z.infer<typeof BrandContextSchema>

// ============================================
// Business profile (TekSocial-compatible shape for AI prompts)
// ============================================
export const BusinessProfileInputSchema = z.object({
  name: z.string().min(2),
  brandVoice: z.string().min(50),
  industry: z.string().min(2),
  website: z.string().url().optional().or(z.literal('')),
  targetAudience: z.string().min(30),
  keyServices: z.string().min(10),
  keyDifferentiators: z.string().optional(),
  primaryGoals: z.string().min(10),
  contentPillars: z.string().optional(),
  preferredPlatforms: z.string().optional(),
  toneKeywords: z.string().optional(),
  doNotSay: z.string().optional(),
  visualStyle: z.string().optional(),
  logoDataUrl: z.string().optional(),
  additionalContext: z.string().optional(),
})

export type BusinessProfileInput = z.infer<typeof BusinessProfileInputSchema>

export interface BusinessProfile extends BusinessProfileInput {
  id: string
  createdAt: string
  updatedAt: string
}

// ============================================
// Social Platforms (Content Studio)
// ============================================
export const SocialPlatformSchema = z.enum([
  'youtube_short',
  'youtube_long',
  'tiktok',
  'instagram',
  'x',
  'linkedin',
  'facebook',
])
export type SocialPlatform = z.infer<typeof SocialPlatformSchema>

export const ScenePromptSchema = z.object({
  sceneNumber: z.number(),
  description: z.string(),
  prompt: z.string(),
})

export const ThumbnailSchema = z.object({
  concept: z.string(),
  prompt: z.string(),
})

export const YouTubeMetadataSchema = z.object({
  titleOptions: z.array(z.string()).min(3).max(5),
  description: z.string(),
  tags: z.array(z.string()).min(5),
})

export const VideoScriptSchema = z.object({
  hook: z.string().min(1),
  body: z.string().min(1),
  cta: z.string().min(1),
  estimatedDurationSec: z.number().min(30).max(600).default(75),
})

export const SocialPostFormatSchema = z.enum(['POST', 'THREAD', 'CAROUSEL'])
export const InstagramFormatSchema = z.enum(['REEL', 'POST', 'CAROUSEL', 'STORY'])

export const YouTubeShortContentSchema = z.object({
  script: VideoScriptSchema,
  imagePrompts: z.array(ScenePromptSchema).min(4).max(6),
  thumbnail: ThumbnailSchema,
  youtube: YouTubeMetadataSchema,
})

export const YouTubeLongContentSchema = z.object({
  outline: z.array(
    z.object({
      section: z.string(),
      durationSec: z.number(),
      talkingPoints: z.array(z.string()),
    })
  ),
  script: z.string().min(100),
  brollPrompts: z.array(ScenePromptSchema).min(6).max(12),
  thumbnail: ThumbnailSchema,
  youtube: YouTubeMetadataSchema,
})

export const TikTokContentSchema = z.object({
  script: VideoScriptSchema,
  onScreenText: z.array(z.string()).min(3).max(8),
  hashtags: z.array(z.string()).min(5).max(15),
  scenePrompts: z.array(ScenePromptSchema).min(4).max(6),
  musicMood: z.string().optional(),
  caption: z.string(),
})

export const SocialPostContentSchema = z.object({
  format: SocialPostFormatSchema.default('POST'),
  hook: z.string().min(1),
  body: z.string().min(1),
  hashtags: z.array(z.string()).min(3).max(10),
  suggestedMedia: z.string().optional(),
  imagePrompt: z.string().optional(),
  cta: z.string().optional(),
})

export const InstagramContentSchema = z.object({
  format: InstagramFormatSchema.default('REEL'),
  caption: z.string().min(1),
  hook: z.string().min(1),
  hashtags: z.array(z.string()).min(5).max(30),
  reelScript: VideoScriptSchema.optional(),
  carouselSlides: z
    .array(
      z.object({
        slideNumber: z.number(),
        headline: z.string(),
        body: z.string(),
        imagePrompt: z.string(),
      })
    )
    .optional(),
  imagePrompt: z.string().optional(),
})

export const PlatformContentSchema = z.object({
  youtube_short: YouTubeShortContentSchema.optional(),
  youtube_long: YouTubeLongContentSchema.optional(),
  tiktok: TikTokContentSchema.optional(),
  instagram: InstagramContentSchema.optional(),
  x: SocialPostContentSchema.optional(),
  linkedin: SocialPostContentSchema.optional(),
  facebook: SocialPostContentSchema.optional(),
})

export type PlatformContent = z.infer<typeof PlatformContentSchema>
export type SocialPostContent = z.infer<typeof SocialPostContentSchema>

export const ContentEpisodePayloadSchema = z
  .object({
    platforms: z.array(SocialPlatformSchema).min(1),
    strategyNote: z.string().min(20),
    agentReasoning: z.string().min(20),
    content: PlatformContentSchema,
  })
  .refine(
    (data) => data.platforms.every((platform) => data.content[platform] !== undefined),
    { message: 'Each selected platform must have corresponding content' }
  )

export type ContentEpisodePayload = z.infer<typeof ContentEpisodePayloadSchema>

export interface ContentEpisode extends ContentEpisodePayload {
  id: string
  businessId: string
  topic: string
  provider: AIProvider
  createdAt: string
}

// ============================================
// Planning cycle (autonomous agent)
// ============================================
export const ContentProposalSchema = z.object({
  platform: z.enum(['X', 'LINKEDIN']).default('X'),
  format: z.enum(['POST', 'THREAD', 'CAROUSEL', 'IMAGE', 'VIDEO']).default('POST'),
  title: z.string().optional(),
  body: z.string().min(1).default(''),
  suggestedMedia: z.string().optional(),
  agentReasoning: z.string().min(1).default('Generated by agent'),
  confidence: z.number().min(0).max(1).default(0.65),
})

export type ContentProposal = z.infer<typeof ContentProposalSchema>

export const PlanningCycleResultSchema = z.object({
  strategyNote: z.string().min(20),
  proposals: z.array(ContentProposalSchema).min(1).max(8),
})

export type PlanningCycleResult = z.infer<typeof PlanningCycleResultSchema>

export interface AgentContext {
  brand: unknown
  recentActivity: unknown[]
  recentContent: unknown[]
}

import OpenAI from "openai";
import type { AIProvider } from "@/lib/agent/types";
import {
  DALLE3_SIZES,
  GROK_ASPECT_RATIOS,
  IMAGE_COST_ESTIMATES,
  IMAGE_PROVIDER_CONFIG,
  type ImageAspectRatio,
} from "@/lib/constants/image-generation";

export interface GeneratedImage {
  base64: string;
  mimeType: "image/png" | "image/jpeg" | "image/webp";
  revisedPrompt?: string;
}

export interface GenerateImageResult {
  image: GeneratedImage;
  provider: AIProvider;
  model: string;
  estimatedCostUsd: number;
}

interface GenerateImageParams {
  provider: Extract<AIProvider, "openai" | "google" | "xai">;
  apiKey: string;
  prompt: string;
  aspectRatio?: ImageAspectRatio;
}

export async function generateImage(
  params: GenerateImageParams
): Promise<GenerateImageResult> {
  const { provider, apiKey, prompt, aspectRatio = "landscape" } = params;

  if (!apiKey?.trim()) {
    throw new Error("API key is required");
  }
  if (!prompt?.trim()) {
    throw new Error("Image prompt is required");
  }

  const config = IMAGE_PROVIDER_CONFIG[provider];

  switch (provider) {
    case "openai":
      return generateOpenAIImage({
        apiKey,
        prompt: prompt.trim(),
        model: config.model,
        aspectRatio,
      });
    case "google":
      return generateGoogleImage({
        apiKey,
        prompt: prompt.trim(),
        model: config.model,
      });
    case "xai":
      return generateXAIImage({
        apiKey,
        prompt: prompt.trim(),
        model: config.model,
        aspectRatio,
      });
    default:
      throw new Error(`Image generation is not supported for ${provider}`);
  }
}

async function generateOpenAIImage({
  apiKey,
  prompt,
  model,
  aspectRatio,
}: {
  apiKey: string;
  prompt: string;
  model: string;
  aspectRatio: ImageAspectRatio;
}): Promise<GenerateImageResult> {
  const client = new OpenAI({ apiKey });
  const size = DALLE3_SIZES[aspectRatio];

  const response = await client.images.generate({
    model,
    prompt,
    n: 1,
    size,
    response_format: "b64_json",
    quality: "standard",
  });

  const item = response.data?.[0];
  if (!item?.b64_json) {
    throw new Error("OpenAI returned no image data");
  }

  return {
    image: {
      base64: item.b64_json,
      mimeType: "image/png",
      revisedPrompt: item.revised_prompt ?? undefined,
    },
    provider: "openai",
    model,
    estimatedCostUsd: IMAGE_COST_ESTIMATES[model] ?? 0.04,
  };
}

async function generateGoogleImage({
  apiKey,
  prompt,
  model,
}: {
  apiKey: string;
  prompt: string;
  model: string;
}): Promise<GenerateImageResult> {
  const url = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${encodeURIComponent(apiKey)}`;

  const response = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      contents: [{ role: "user", parts: [{ text: prompt }] }],
      generationConfig: {
        responseModalities: ["TEXT", "IMAGE"],
      },
    }),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Google image generation failed (${response.status}): ${errorText}`);
  }

  const data = await response.json();
  const parts = data.candidates?.[0]?.content?.parts ?? [];

  for (const part of parts) {
    const inline = part.inlineData ?? part.inline_data;
    if (!inline?.data) continue;

    const mimeType = (inline.mimeType ?? inline.mime_type ?? "image/png") as
      | "image/png"
      | "image/jpeg"
      | "image/webp";

    return {
      image: { base64: inline.data, mimeType },
      provider: "google",
      model,
      estimatedCostUsd: IMAGE_COST_ESTIMATES[model] ?? 0.03,
    };
  }

  throw new Error("Google returned no image data. Try OpenAI (DALL·E 3) if this persists.");
}

async function generateXAIImage({
  apiKey,
  prompt,
  model,
  aspectRatio,
}: {
  apiKey: string;
  prompt: string;
  model: string;
  aspectRatio: ImageAspectRatio;
}): Promise<GenerateImageResult> {
  const response = await fetch("https://api.x.ai/v1/images/generations", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model,
      prompt,
      aspect_ratio: GROK_ASPECT_RATIOS[aspectRatio],
      response_format: "b64_json",
    }),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`xAI image generation failed (${response.status}): ${errorText}`);
  }

  const data = await response.json();
  const item = data.data?.[0];

  if (item?.b64_json) {
    return {
      image: {
        base64: item.b64_json,
        mimeType: "image/png",
        revisedPrompt: item.revised_prompt ?? undefined,
      },
      provider: "xai",
      model,
      estimatedCostUsd: IMAGE_COST_ESTIMATES[model] ?? 0.05,
    };
  }

  if (item?.url) {
    const imageResponse = await fetch(item.url);
    if (!imageResponse.ok) {
      throw new Error("Failed to download image from xAI URL");
    }
    const buffer = await imageResponse.arrayBuffer();
    const base64 = Buffer.from(buffer).toString("base64");
    const mimeType =
      imageResponse.headers.get("content-type")?.split(";")[0] ?? "image/png";

    return {
      image: {
        base64,
        mimeType: mimeType as GeneratedImage["mimeType"],
        revisedPrompt: item.revised_prompt ?? undefined,
      },
      provider: "xai",
      model,
      estimatedCostUsd: IMAGE_COST_ESTIMATES[model] ?? 0.05,
    };
  }

  throw new Error("xAI returned no image data");
}

import { describe, expect, it } from 'vitest'
import {
  parseJsonResponse,
  safeParseJsonResponse,
  stripJsonFences,
} from '@/lib/ai/parse-response'

describe('stripJsonFences', () => {
  it('removes markdown code fences', () => {
    const raw = '```json\n{"ok": true}\n```'
    expect(stripJsonFences(raw)).toBe('{"ok": true}')
  })
})

describe('parseJsonResponse', () => {
  it('parses clean JSON', () => {
    expect(parseJsonResponse('{"a": 1}')).toEqual({ a: 1 })
  })
})

describe('safeParseJsonResponse', () => {
  it('returns null on invalid JSON', () => {
    expect(safeParseJsonResponse('not json')).toBeNull()
  })

  it('parses fenced JSON', () => {
    const result = safeParseJsonResponse('```json\n{"topic": "test"}\n```')
    expect(result).toEqual({ topic: 'test' })
  })
})

export function stripJsonFences(raw: string): string {
  return raw.replace(/```json\s*/gi, "").replace(/```/g, "").trim();
}

export function parseJsonResponse<T = Record<string, unknown>>(raw: string): T {
  const cleaned = stripJsonFences(raw);
  return JSON.parse(cleaned) as T;
}

export function safeParseJsonResponse<T = Record<string, unknown>>(
  raw: string
): T | null {
  try {
    return parseJsonResponse<T>(raw);
  } catch {
    return null;
  }
}

import OpenAI from "openai";
import Anthropic from "@anthropic-ai/sdk";
import type { AIProvider } from "@/lib/agent/types";
import { getDefaultModel } from "@/lib/constants/ai-providers";
import { estimateCost, type TokenUsage } from "@/lib/ai/usage";

export interface ChatMessage {
  role: "system" | "user" | "assistant";
  content: string;
}

export interface ProviderCallResult {
  content: string;
  model: string;
  provider: AIProvider;
  usage: TokenUsage & { estimatedCostUsd?: number };
}

interface CallProviderParams {
  provider: AIProvider;
  apiKey: string;
  messages: ChatMessage[];
  model?: string;
  temperature?: number;
  jsonMode?: boolean;
  maxTokens?: number;
}

export async function callProvider(
  params: CallProviderParams
): Promise<ProviderCallResult> {
  const {
    provider,
    apiKey,
    messages,
    model = getDefaultModel(provider),
    temperature = 0.4,
    jsonMode = false,
    maxTokens = 4096,
  } = params;

  if (!apiKey?.trim()) {
    throw new Error("API key is required");
  }

  switch (provider) {
    case "openai":
      return callOpenAI({ apiKey, messages, model, temperature, jsonMode, maxTokens });
    case "anthropic":
      return callAnthropic({ apiKey, messages, model, temperature, jsonMode, maxTokens });
    case "xai":
      return callXAI({ apiKey, messages, model, temperature, jsonMode, maxTokens });
    case "google":
      return callGoogle({ apiKey, messages, model, temperature, jsonMode, maxTokens });
    default:
      throw new Error(`Unsupported provider: ${provider}`);
  }
}

async function callOpenAI({
  apiKey,
  messages,
  model: modelParam,
  temperature,
  jsonMode,
  maxTokens = 4096,
}: Omit<CallProviderParams, "provider"> & { apiKey: string }): Promise<ProviderCallResult> {
  const model = modelParam ?? getDefaultModel("openai");
  const client = new OpenAI({ apiKey });

  const response = await client.chat.completions.create({
    model,
    messages,
    temperature,
    max_tokens: maxTokens,
    ...(jsonMode ? { response_format: { type: "json_object" as const } } : {}),
  });

  const content = response.choices[0]?.message?.content ?? "";
  const usage = normalizeUsage(response.usage);

  return {
    content,
    model,
    provider: "openai",
    usage: {
      ...usage,
      estimatedCostUsd: usage.totalTokens
        ? estimateCost(model, usage.totalTokens)
        : undefined,
    },
  };
}

async function callAnthropic({
  apiKey,
  messages,
  model: modelParam,
  temperature,
  jsonMode,
  maxTokens = 4096,
}: Omit<CallProviderParams, "provider"> & { apiKey: string }): Promise<ProviderCallResult> {
  const model = modelParam ?? getDefaultModel("anthropic");
  const client = new Anthropic({ apiKey });

  const systemMessage = messages.find((m) => m.role === "system")?.content;
  const chatMessages = messages
    .filter((m) => m.role !== "system")
    .map((m) => ({
      role: m.role as "user" | "assistant",
      content: m.content,
    }));

  const response = await client.messages.create({
    model,
    max_tokens: maxTokens,
    temperature,
    system: jsonMode
      ? `${systemMessage ?? ""}\n\nRespond with valid JSON only.`.trim()
      : systemMessage,
    messages: chatMessages.length > 0 ? chatMessages : [{ role: "user", content: "Hello" }],
  });

  const textBlock = response.content.find((block) => block.type === "text");
  const content = textBlock && "text" in textBlock ? textBlock.text : "";

  const totalTokens =
    (response.usage.input_tokens ?? 0) + (response.usage.output_tokens ?? 0);

  return {
    content,
    model,
    provider: "anthropic",
    usage: {
      promptTokens: response.usage.input_tokens,
      completionTokens: response.usage.output_tokens,
      totalTokens,
      estimatedCostUsd: estimateCost(model, totalTokens),
    },
  };
}

async function callXAI({
  apiKey,
  messages,
  model: modelParam,
  temperature,
  jsonMode,
  maxTokens = 4096,
}: Omit<CallProviderParams, "provider"> & { apiKey: string }): Promise<ProviderCallResult> {
  const model = modelParam ?? getDefaultModel("xai");
  const response = await fetch("https://api.x.ai/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model,
      messages,
      temperature,
      max_tokens: maxTokens,
      ...(jsonMode ? { response_format: { type: "json_object" } } : {}),
    }),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`xAI request failed (${response.status}): ${errorText}`);
  }

  const data = await response.json();
  const content = data.choices?.[0]?.message?.content ?? "";
  const usage = normalizeUsage(data.usage);

  return {
    content,
    model,
    provider: "xai",
    usage: {
      ...usage,
      estimatedCostUsd: usage.totalTokens
        ? estimateCost(model, usage.totalTokens)
        : undefined,
    },
  };
}

async function callGoogle({
  apiKey,
  messages,
  model: modelParam,
  temperature,
  jsonMode,
  maxTokens = 8192,
}: Omit<CallProviderParams, "provider"> & { apiKey: string }): Promise<ProviderCallResult> {
  const model = modelParam ?? getDefaultModel("google");

  const systemMessage = messages.find((m) => m.role === "system")?.content;
  const contents = messages
    .filter((m) => m.role !== "system")
    .map((m) => ({
      role: m.role === "assistant" ? "model" : "user",
      parts: [{ text: m.content }],
    }));

  const body: Record<string, unknown> = {
    contents:
      contents.length > 0
        ? contents
        : [{ role: "user", parts: [{ text: "Hello" }] }],
    generationConfig: {
      temperature,
      maxOutputTokens: maxTokens,
      ...(jsonMode ? { responseMimeType: "application/json" } : {}),
    },
  };

  if (systemMessage) {
    body.systemInstruction = {
      parts: [
        {
          text: jsonMode
            ? `${systemMessage}\n\nRespond with valid JSON only.`
            : systemMessage,
        },
      ],
    };
  }

  const url = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${encodeURIComponent(apiKey)}`;

  const response = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Google AI request failed (${response.status}): ${errorText}`);
  }

  const data = await response.json();
  const content =
    data.candidates?.[0]?.content?.parts
      ?.map((p: { text?: string }) => p.text ?? "")
      .join("") ?? "";

  const meta = data.usageMetadata;
  const promptTokens = meta?.promptTokenCount;
  const completionTokens = meta?.candidatesTokenCount;
  const totalTokens =
    meta?.totalTokenCount ?? (promptTokens ?? 0) + (completionTokens ?? 0);

  return {
    content,
    model,
    provider: "google",
    usage: {
      promptTokens,
      completionTokens,
      totalTokens,
      estimatedCostUsd: totalTokens
        ? estimateCost(model, totalTokens)
        : undefined,
    },
  };
}

function normalizeUsage(
  usage?: {
    prompt_tokens?: number;
    completion_tokens?: number;
    total_tokens?: number;
    input_tokens?: number;
    output_tokens?: number;
  } | null
): TokenUsage {
  if (!usage) return {};

  const promptTokens = usage.prompt_tokens ?? usage.input_tokens;
  const completionTokens = usage.completion_tokens ?? usage.output_tokens;
  const totalTokens =
    usage.total_tokens ?? (promptTokens ?? 0) + (completionTokens ?? 0);

  return { promptTokens, completionTokens, totalTokens };
}
